/*
 * OCR B (Advancing Physics) A-Level Physics (H557) — Exam Practice Question Bank
 * All written/exam-style questions with mark schemes.
 * 250 questions total: 25 for B1, 25 for B2, 50 each for B3–B6.
 */

const PHYSICS_OCR_B_PRACTICE = {

  /* ─────────────────────────────────────────────────────────── B1 */
  'B1': {
    name: 'Development of Practical Skills',
    questions: [
      { q: 'State what is meant by a systematic error.', marks: 1, markScheme: `• An error that causes all readings to differ from the true value by a consistent amount in the same direction (1)` },
      { q: 'State what is meant by a random error.', marks: 1, markScheme: `• An unpredictable variation that causes readings to scatter about the true value (1)` },
      { q: 'Distinguish between accuracy and precision.', marks: 2, markScheme: `• Accuracy is how close a measured value is to the true value (1)\n• Precision is how closely repeated measurements agree with each other / the spread of readings (1)` },
      { q: 'A student measures the thickness of a glass block as 12.4 mm using a ruler with mm divisions. State the absolute uncertainty in this measurement.', marks: 1, markScheme: `• ±0.5 mm (half the smallest division) (1)` },
      { q: 'A student measures a current of 0.48 A with an uncertainty of ±0.02 A and a voltage of 6.0 V with an uncertainty of ±0.1 V. Calculate the percentage uncertainty in the resistance.', marks: 3, markScheme: `• %ΔI = (0.02/0.48) × 100 = 4.2% (1)\n• %ΔV = (0.1/6.0) × 100 = 1.7% (1)\n• %ΔR = 4.2% + 1.7% = 5.9% (accept 5.8–5.9%) (1)` },
      { q: 'Explain why repeating measurements and calculating a mean improves the reliability of an experiment.', marks: 2, markScheme: `• Repeating allows identification and removal of anomalous results (1)\n• Averaging reduces the effect of random errors on the final result (1)` },
      { q: 'Describe how error bars on a graph can be used to determine the uncertainty in the gradient.', marks: 3, markScheme: `• Error bars are drawn on each data point showing the range of uncertainty (1)\n• Lines of steepest and shallowest gradient are drawn through the error bars (1)\n• Uncertainty in gradient = (steepest gradient − shallowest gradient) / 2 (1)` },
      { q: 'A quantity y is related to x by y = kx³. The percentage uncertainty in x is 2%. Calculate the percentage uncertainty in y.', marks: 2, markScheme: `• Percentage uncertainty is multiplied by the power (1)\n• %Δy = 3 × 2% = 6% (1)` },
      { q: 'Explain why plotting T² against l rather than T against l is preferred when investigating a simple pendulum.', marks: 2, markScheme: `• The relationship T = 2π√(l/g) gives T² = (4π²/g)l (1)\n• A graph of T² vs l yields a straight line through the origin, making it easier to verify the relationship and determine g from the gradient (1)` },
      { q: 'A log-log graph of F against v gives a straight line with gradient 2.0 and y-intercept 0.30. Determine the equation relating F and v.', marks: 3, markScheme: `• log F = 2.0 log v + 0.30 means n = 2.0 (1)\n• log k = 0.30, so k = 10^0.30 = 2.0 (1)\n• Therefore F = 2.0v² (1)` },
      { q: 'A student obtains g = 10.1 ± 0.4 m s⁻². The accepted value is 9.81 m s⁻². Evaluate whether the result is consistent with the accepted value.', marks: 3, markScheme: `• Range of result is 9.7 to 10.5 m s⁻² (1)\n• The accepted value 9.81 falls within this range (1)\n• Therefore the result is consistent with the accepted value within stated uncertainty (1)` },
      { q: 'State two advantages of using a data logger over manual data collection.', marks: 2, markScheme: `• Data loggers can record data at much higher sampling rates than manual methods (1)\n• They eliminate human reaction time errors / can record continuously over extended periods (1)` },
      { q: 'Describe how you would use a micrometer screw gauge to accurately measure the diameter of a wire.', marks: 3, markScheme: `• Check and record the zero error before use (1)\n• Place the wire between the anvil and spindle, use the ratchet to close gently to avoid over-tightening (1)\n• Take readings at several points along the wire and at different orientations, then calculate the mean (1)` },
      { q: 'Explain why a student should plot a graph of ln(V) against time t when investigating the discharge of a capacitor, where V = V₀e^(−t/RC).', marks: 3, markScheme: `• Taking natural logs: ln V = ln V₀ − t/RC (1)\n• This has the form y = c + mx (straight line) (1)\n• Gradient = −1/RC, allowing RC to be determined; y-intercept = ln V₀ (1)` },
      { q: 'Suggest why the precision of a measurement made with a stopwatch is limited by factors other than the resolution of the stopwatch.', marks: 2, markScheme: `• The resolution of a stopwatch is typically 0.01 s, but human reaction time is about 0.2−0.3 s (1)\n• Reaction time at start and stop is the dominant source of uncertainty, far exceeding the resolution (1)` },
      { q: 'A student claims that their experiment proves a hypothesis. Explain why this claim is not scientifically valid.', marks: 2, markScheme: `• Scientific experiments can provide evidence to support a hypothesis but cannot definitively prove it (1)\n• There may be alternative explanations, or future experiments could yield contradictory results (1)` },
      { q: 'Describe how to investigate the relationship between the extension of a spring and the applied force, including a suitable graph.', marks: 4, markScheme: `• Hang the spring vertically, add known masses one at a time, recording the mass and the extension (change from natural length) (1)\n• Repeat each loading at least three times and calculate the mean extension (1)\n• Plot a graph of force (F = mg) on the x-axis against extension on the y-axis (1)\n• The gradient of the linear region gives 1/k (or plot extension vs force for gradient = 1/k); identify the limit of proportionality where the graph deviates from linearity (1)` },
      { q: 'Explain what is meant by the resolution of a measuring instrument and give an example.', marks: 2, markScheme: `• The smallest change in the quantity being measured that the instrument can detect (1)\n• Example: a ruler with mm markings has a resolution of 1 mm / a micrometer has a resolution of 0.01 mm (1)` },
      { q: 'A student measures the period of oscillation by timing 20 complete swings. Explain why this method reduces the percentage uncertainty compared to timing a single swing.', marks: 2, markScheme: `• The total time for 20 swings is much larger, so the fixed reaction time uncertainty becomes a smaller fraction of the measured time (1)\n• Dividing the total time by 20 gives a period with a much smaller absolute uncertainty than timing one swing directly (1)` },
      { q: 'Explain why control variables must be kept constant in an experiment.', marks: 2, markScheme: `• To ensure that changes in the dependent variable are caused only by changes in the independent variable (1)\n• Otherwise confounding factors could affect the results, making the experiment invalid / not a fair test (1)` },
      { q: 'State what is meant by the term "fiducial marker" and explain when one would be used.', marks: 2, markScheme: `• A fixed reference point used to reduce parallax error when taking a reading (1)\n• Used for example as a marker at the equilibrium position of a pendulum, or a line drawn on a vibrating object to mark a specific position (1)` },
      { q: 'The gradient of a straight-line graph is found to be 4.8 and the uncertainty in the gradient is ±0.3. Express this as a percentage uncertainty.', marks: 2, markScheme: `• Percentage uncertainty = (0.3/4.8) × 100 (1)\n• = 6.25% ≈ 6.3% (1)` },
      { q: 'Explain why you should avoid zero errors when using measuring instruments. State how to deal with a zero error.', marks: 2, markScheme: `• A zero error is a systematic error that shifts all readings by a fixed amount from the true value (1)\n• Record the zero error before measurements and subtract (or add) it from all subsequent readings to correct for it (1)` },
      { q: 'Describe how you would determine whether two variables are inversely proportional using graphical methods.', marks: 3, markScheme: `• Plot y against 1/x (1)\n• If the relationship is y = k/x, the graph should be a straight line through the origin (1)\n• The gradient gives the constant of proportionality k; a non-zero intercept or curvature indicates the relationship is not a simple inverse proportion (1)` },
      { q: 'Evaluate the following statement: "A precise experiment always gives accurate results."', marks: 3, markScheme: `• This statement is incorrect (1)\n• High precision means repeated measurements are close together (small random error) but they could all be shifted from the true value by a systematic error (1)\n• For example, a miscalibrated instrument gives precise but inaccurate readings; accuracy requires both low random and low systematic error (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B2 */
  'B2': {
    name: 'Fundamental Data Analysis',
    questions: [
      { q: 'State what is meant by a scalar quantity and give two examples.', marks: 2, markScheme: `• A quantity with magnitude only and no direction (1)\n• Examples: mass, temperature, speed, energy (any two acceptable) (1)` },
      { q: 'State what is meant by a vector quantity and give two examples.', marks: 2, markScheme: `• A quantity with both magnitude and direction (1)\n• Examples: velocity, force, acceleration, displacement (any two acceptable) (1)` },
      { q: 'Explain the importance of SI units in physics.', marks: 2, markScheme: `• SI units provide a standardised, internationally agreed system of measurement (1)\n• This ensures consistency and allows results from different experiments and countries to be compared meaningfully (1)` },
      { q: 'Show that the SI base units of energy (joule) are kg m² s⁻².', marks: 2, markScheme: `• Energy = force × distance = (mass × acceleration) × distance (1)\n• Units: kg × m s⁻² × m = kg m² s⁻² (1)` },
      { q: 'Convert a pressure of 150 kPa into Pa using standard form.', marks: 1, markScheme: `• 150 kPa = 1.50 × 10⁵ Pa (1)` },
      { q: 'A student records a speed of 3.0 × 10⁸ m s⁻¹ and a time of 2.0 × 10⁻⁹ s. Calculate the distance travelled.', marks: 2, markScheme: `• d = v × t = 3.0 × 10⁸ × 2.0 × 10⁻⁹ (1)\n• = 0.60 m (1)` },
      { q: 'Explain the difference between an estimate and an exact calculation in physics.', marks: 2, markScheme: `• An estimate uses approximations and rounded values to obtain an order-of-magnitude or rough answer quickly (1)\n• An exact calculation uses precise measured values and appropriate equations to obtain an answer to a stated number of significant figures (1)` },
      { q: 'Estimate the number of heartbeats in an average human lifetime. Show your reasoning.', marks: 3, markScheme: `• Assume heart rate ≈ 70 beats per minute and lifetime ≈ 80 years (1)\n• Minutes in a lifetime ≈ 80 × 365 × 24 × 60 ≈ 4.2 × 10⁷ minutes (1)\n• Total beats ≈ 70 × 4.2 × 10⁷ ≈ 3 × 10⁹ (accept 2–4 × 10⁹) (1)` },
      { q: 'A force of 12 N acts at 30° to the horizontal. Calculate the horizontal and vertical components of the force.', marks: 2, markScheme: `• Horizontal: F cos 30° = 12 × cos 30° = 10.4 N (1)\n• Vertical: F sin 30° = 12 × sin 30° = 6.0 N (1)` },
      { q: 'Two forces of 5.0 N and 8.0 N act at right angles to each other. Calculate the magnitude and direction of the resultant force.', marks: 3, markScheme: `• Resultant = √(5.0² + 8.0²) = √(25 + 64) = √89 = 9.4 N (1)\n• θ = tan⁻¹(5.0/8.0) = 32° (1)\n• The resultant is 9.4 N at 32° to the 8.0 N force (1)` },
      { q: 'Explain what is meant by homogeneity of a physical equation and why it is useful.', marks: 2, markScheme: `• A homogeneous equation has the same units/dimensions on both sides (1)\n• Checking homogeneity is useful as a quick check that an equation could be correct — if the units do not match, the equation must be wrong (1)` },
      { q: 'Verify that the equation v² = u² + 2as is homogeneous in terms of SI base units.', marks: 3, markScheme: `• LHS: v² has units (m s⁻¹)² = m² s⁻² (1)\n• u² also has units m² s⁻² (1)\n• 2as has units m s⁻² × m = m² s⁻², which matches the LHS, so the equation is homogeneous (1)` },
      { q: 'Explain the difference between a linear and a non-linear relationship between two variables.', marks: 2, markScheme: `• A linear relationship gives a straight-line graph when the two variables are plotted against each other (y = mx + c) (1)\n• A non-linear relationship gives a curved graph, e.g. quadratic, exponential, or inverse relationships (1)` },
      { q: 'A graph of T² against m gives a straight line through the origin with gradient 4.0 s² kg⁻¹. If T² = (4π²/k)m, determine the value of k.', marks: 3, markScheme: `• Gradient = 4π²/k = 4.0 (1)\n• k = 4π²/4.0 (1)\n• k = 9.87 ≈ 9.9 N m⁻¹ (1)` },
      { q: 'A variable y decays exponentially with time t. Sketch the expected shape of (i) y against t, (ii) ln y against t.', marks: 2, markScheme: `• (i) An exponential decay curve starting at y₀ and decreasing towards zero, never reaching it (1)\n• (ii) A straight line with negative gradient (since ln y = ln y₀ − kt) (1)` },
      { q: 'State the conditions under which it is appropriate to use the small angle approximations sin θ ≈ θ and cos θ ≈ 1.', marks: 2, markScheme: `• These approximations are valid when the angle θ is small, typically less than about 10° (1)\n• The angle θ must be measured in radians for the approximations to apply (1)` },
      { q: 'Express the unit of the Planck constant h in SI base units, given that E = hf.', marks: 2, markScheme: `• E is in joules = kg m² s⁻² and f is in s⁻¹ (1)\n• h = E/f, so units of h = kg m² s⁻² / s⁻¹ = kg m² s⁻¹ (1)` },
      { q: 'A student uses a spreadsheet to calculate the mean and standard deviation of 50 measurements. Explain the significance of the standard deviation.', marks: 2, markScheme: `• The standard deviation quantifies the spread/dispersion of the data about the mean (1)\n• A smaller standard deviation means the data points are clustered closely around the mean, indicating higher precision / less random variation (1)` },
      { q: 'Explain why using a graph to determine a physical quantity is generally more reliable than using a single pair of readings.', marks: 3, markScheme: `• A graph uses all data points, not just one measurement (1)\n• It allows anomalous points to be identified and excluded (1)\n• A line of best fit averages out random errors across the data set, giving a more reliable value (1)` },
      { q: 'The speed of sound in air is approximately 340 m s⁻¹. Estimate the wavelength of a sound wave with frequency 1.0 kHz.', marks: 2, markScheme: `• λ = v/f = 340/1000 (1)\n• = 0.34 m (1)` },
      { q: 'Explain what is meant by an order of magnitude estimate and state its purpose.', marks: 2, markScheme: `• An order of magnitude estimate gives a value rounded to the nearest power of 10 (1)\n• It is used as a quick check of reasonableness, to compare scales, or to verify that a calculated answer is sensible (1)` },
      { q: 'Show that the unit of electrical resistance (ohm) can be expressed as kg m² s⁻³ A⁻².', marks: 3, markScheme: `• V = IR, so R = V/I; and V = W/Q = (energy)/(charge) (1)\n• Units of V = kg m² s⁻² / (A s) = kg m² s⁻³ A⁻¹ (1)\n• Units of R = V/I = kg m² s⁻³ A⁻¹ / A = kg m² s⁻³ A⁻² (1)` },
      { q: 'A student states that an object has a mass of 2.50000 kg. Explain why this level of precision may not be justified.', marks: 2, markScheme: `• The number of significant figures quoted should reflect the precision of the measuring instrument (1)\n• Quoting 6 significant figures implies a balance accurate to ±0.00001 kg, which is unlikely for a standard laboratory balance (1)` },
      { q: 'A body moves with velocity v = (3i + 4j) m s⁻¹. Calculate the speed of the body.', marks: 2, markScheme: `• Speed = |v| = √(3² + 4²) = √(9 + 16) (1)\n• = √25 = 5.0 m s⁻¹ (1)` },
      { q: 'Explain the principle of superposition as applied to adding vectors graphically.', marks: 2, markScheme: `• Vectors are added tip-to-tail: the second vector is drawn from the tip of the first (1)\n• The resultant is the vector drawn from the tail of the first to the tip of the last vector added (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B3 */
  'B3': {
    name: 'Physics in Action',
    questions: [
      // --- Imaging ---
      { q: 'State what is meant by the magnification of an image formed by a lens.', marks: 1, markScheme: `• Magnification is the ratio of image height to object height (or image distance to object distance) (1)` },
      { q: 'A converging lens of focal length 10 cm forms an image of an object placed 30 cm from the lens. Calculate the image distance using the thin lens equation.', marks: 3, markScheme: `• 1/v = 1/f − 1/u = 1/10 − 1/30 (1)\n• 1/v = 3/30 − 1/30 = 2/30 (1)\n• v = 15 cm (1)` },
      { q: 'State the Rayleigh criterion for the resolution of two point sources.', marks: 2, markScheme: `• Two sources are just resolved when the central maximum of one diffraction pattern falls on the first minimum of the other (1)\n• The minimum angular resolution is given by θ ≈ λ/D where D is the aperture diameter (1)` },
      { q: 'Explain why a larger telescope aperture gives better resolution.', marks: 2, markScheme: `• The angular resolution θ ≈ λ/D, so a larger D gives a smaller θ (1)\n• A smaller minimum resolvable angle means finer detail can be distinguished / closer objects can be separated (1)` },
      { q: 'A microscope objective has a diameter of 5.0 mm and uses light of wavelength 550 nm. Calculate the minimum angle that can be resolved.', marks: 2, markScheme: `• θ = λ/D = 550 × 10⁻⁹ / 5.0 × 10⁻³ (1)\n• = 1.1 × 10⁻⁴ rad (1)` },
      { q: 'Explain why electron microscopes can achieve higher resolution than optical microscopes.', marks: 2, markScheme: `• Electrons can have a much shorter de Broglie wavelength than visible light (1)\n• Since resolution limit ∝ wavelength, shorter wavelength gives better (smaller) resolution limit (1)` },
      { q: 'State what is meant by the focal length of a converging lens.', marks: 1, markScheme: `• The distance from the centre of the lens to the principal focus, where parallel rays of light converge after passing through the lens (1)` },
      { q: 'Describe how you would experimentally determine the focal length of a converging lens using a distant object.', marks: 2, markScheme: `• Point the lens at a very distant object (e.g. a window or tree) so that incoming rays are approximately parallel (1)\n• Move a screen behind the lens until a sharp image is formed; the distance from the lens to the screen is the focal length (1)` },

      // --- Digital imaging ---
      { q: 'Explain what is meant by a pixel in the context of a digital image.', marks: 1, markScheme: `• A pixel is the smallest individual element of a digital image, each storing a value representing colour or brightness (1)` },
      { q: 'A digital image is 1920 × 1080 pixels with a bit depth of 24 bits per pixel. Calculate the file size in megabytes (1 MB = 10⁶ bytes).', marks: 3, markScheme: `• Total pixels = 1920 × 1080 = 2,073,600 (1)\n• Total bits = 2,073,600 × 24 = 49,766,400 bits (1)\n• File size = 49,766,400 / 8 / 10⁶ = 6.2 MB (accept 6.22 MB or 5.93 MiB) (1)` },
      { q: 'Explain how increasing the bit depth of a digital image affects the image quality and file size.', marks: 2, markScheme: `• Greater bit depth means more possible brightness/colour levels per pixel, giving smoother colour gradients and better image quality (1)\n• Each pixel requires more data to store, so the file size increases (1)` },
      { q: 'State what is meant by the sampling rate in the context of digitising an analogue signal.', marks: 1, markScheme: `• The number of samples (measurements of the signal amplitude) taken per unit time / per second (1)` },

      // --- Materials ---
      { q: 'Define the Young modulus of a material.', marks: 1, markScheme: `• The ratio of tensile stress to tensile strain within the limit of proportionality: E = σ/ε = (F/A)/(ΔL/L) (1)` },
      { q: 'A wire of original length 2.0 m and cross-sectional area 1.5 × 10⁻⁶ m² extends by 0.80 mm when a force of 60 N is applied. Calculate the Young modulus.', marks: 3, markScheme: `• Stress = F/A = 60 / (1.5 × 10⁻⁶) = 4.0 × 10⁷ Pa (1)\n• Strain = ΔL/L = 0.80 × 10⁻³ / 2.0 = 4.0 × 10⁻⁴ (1)\n• E = stress/strain = 4.0 × 10⁷ / 4.0 × 10⁻⁴ = 1.0 × 10¹¹ Pa (1)` },
      { q: 'Describe the difference between elastic and plastic deformation.', marks: 2, markScheme: `• Elastic deformation: the material returns to its original shape and size when the deforming force is removed (1)\n• Plastic deformation: the material is permanently deformed and does not return to its original shape when the force is removed (1)` },
      { q: 'Sketch a typical stress-strain graph for a ductile metal such as copper, labelling the elastic limit, yield point, and ultimate tensile stress.', marks: 4, markScheme: `• Initial linear region (Hooke's law) up to the limit of proportionality (1)\n• Elastic limit labelled at or near the end of the linear region (1)\n• Yield point labelled where plastic deformation begins / the stress at which strain increases rapidly with little increase in stress (1)\n• Ultimate tensile stress (UTS) labelled at the maximum stress before the material necks and fractures (1)` },
      { q: 'A rubber band and a metal spring are both stretched and released. Compare the energy changes in each case.', marks: 3, markScheme: `• Both store elastic potential energy when stretched (1)\n• The metal spring (within elastic limit) returns all stored energy — the loading and unloading curves are identical (1)\n• The rubber band exhibits hysteresis — the unloading curve is below the loading curve, so some energy is converted to internal (thermal) energy and not all is recovered (1)` },
      { q: 'Explain why a thick, short wire is used instead of a thin, long wire when a stiff support is needed.', marks: 2, markScheme: `• A larger cross-sectional area gives greater stiffness as extension ∝ 1/A (for the same force and material) (1)\n• A shorter original length gives less extension as extension ∝ L, so the combination minimises deformation under load (1)` },
      { q: 'State what is meant by the elastic limit of a material.', marks: 1, markScheme: `• The maximum stress (or force) that can be applied to a material beyond which it will not return to its original shape when the stress is removed (1)` },
      { q: 'Describe an experiment to determine the Young modulus of a metal wire. Include the measurements needed and how the result is obtained.', marks: 6, markScheme: `• Use a long thin wire clamped at one end, with a ruler or travelling microscope to measure extension and a reference wire to compensate for thermal expansion (1)\n• Measure the original length L of the wire with a metre rule (1)\n• Measure the diameter d of the wire at several points using a micrometer, then calculate cross-sectional area A = πd²/4 (1)\n• Add known masses incrementally, recording the extension ΔL for each load F = mg (1)\n• Plot a graph of stress (F/A) against strain (ΔL/L) (1)\n• The gradient of the straight-line region gives the Young modulus E (1)` },

      // --- Sensing ---
      { q: 'Draw a circuit diagram for a potential divider and explain how the output voltage varies when one of the resistors is changed.', marks: 3, markScheme: `• Correct circuit diagram: two resistors R₁ and R₂ in series across a supply voltage Vₛ, with output taken across R₂ (1)\n• V_out = Vₛ × R₂/(R₁ + R₂) (1)\n• If R₂ increases (or R₁ decreases), V_out increases; if R₂ decreases (or R₁ increases), V_out decreases (1)` },
      { q: 'A thermistor has a resistance of 5000 Ω at 20 °C and 500 Ω at 80 °C. It is connected in series with a 1000 Ω resistor across a 6.0 V supply. Calculate the output voltage across the thermistor at each temperature.', marks: 4, markScheme: `• At 20 °C: V = 6.0 × 5000/(5000 + 1000) = 6.0 × 5000/6000 (1)\n• = 5.0 V (1)\n• At 80 °C: V = 6.0 × 500/(500 + 1000) = 6.0 × 500/1500 (1)\n• = 2.0 V (1)` },
      { q: 'Explain what is meant by the sensitivity of a sensor.', marks: 2, markScheme: `• Sensitivity is the change in output (e.g. voltage) per unit change in the quantity being measured (1)\n• A more sensitive sensor produces a larger output change for a given change in input (1)` },
      { q: 'State two desirable characteristics of a sensor other than high sensitivity.', marks: 2, markScheme: `• Wide range: able to measure over a large range of the input quantity (1)\n• Fast response time / linearity / low drift / high resolution (any one additional valid characteristic) (1)` },
      { q: 'A light-dependent resistor (LDR) is used in a potential divider to detect changes in light level. Explain how the circuit can be arranged so that the output voltage increases as light intensity increases.', marks: 3, markScheme: `• Place the LDR as R₁ (top resistor) and a fixed resistor as R₂ (bottom resistor) with the output taken across R₂ (1)\n• As light intensity increases, the resistance of the LDR decreases (1)\n• With R₁ decreasing, a greater share of the voltage falls across R₂, so V_out increases (1)` },

      // --- Signalling ---
      { q: 'Explain the difference between an analogue signal and a digital signal.', marks: 2, markScheme: `• An analogue signal varies continuously and can take any value within a range (1)\n• A digital signal has only discrete values, typically represented as a series of binary (0 or 1) levels (1)` },
      { q: 'State one advantage of transmitting data digitally rather than in analogue form.', marks: 1, markScheme: `• Digital signals can be regenerated exactly, removing noise picked up during transmission; analogue signals amplify the noise with the signal (1)` },
      { q: 'Explain what noise is in the context of signal transmission and how it affects analogue signals differently from digital signals.', marks: 3, markScheme: `• Noise is unwanted random electrical variations that are added to a signal during transmission (1)\n• In an analogue signal, noise distorts the signal and cannot be separated from it, degrading quality (1)\n• In a digital signal, as long as the noise does not change a 1 to a 0 (or vice versa), the original signal can be perfectly regenerated (1)` },
      { q: 'State the Nyquist theorem (sampling theorem) and explain its significance.', marks: 2, markScheme: `• The sampling frequency must be at least twice the highest frequency present in the signal to accurately reconstruct it (1)\n• If the sampling rate is too low, aliasing occurs and the original signal cannot be faithfully reproduced (1)` },
      { q: 'An audio signal contains frequencies up to 20 kHz. State the minimum sampling rate needed to digitise this signal accurately.', marks: 1, markScheme: `• Minimum sampling rate = 2 × 20 kHz = 40 kHz (1)` },
      { q: 'Calculate the number of possible signal levels if the bit depth is 8 bits.', marks: 1, markScheme: `• Number of levels = 2⁸ = 256 (1)` },
      { q: 'Explain why increasing the sampling rate and bit depth improves the quality of a digitised signal but increases the data rate.', marks: 3, markScheme: `• Higher sampling rate captures more rapid changes in the signal, preserving higher frequency detail (1)\n• Greater bit depth gives finer resolution of amplitude, reducing quantisation error (1)\n• Both increase the amount of data generated per second (data rate = sampling rate × bit depth), requiring more bandwidth for transmission or storage (1)` },
      { q: 'A signal is sampled at 44,100 Hz with a bit depth of 16 bits in stereo (2 channels). Calculate the data rate in kilobits per second.', marks: 3, markScheme: `• Data rate = sampling rate × bit depth × channels (1)\n• = 44,100 × 16 × 2 = 1,411,200 bits per second (1)\n• = 1411.2 kbit s⁻¹ ≈ 1410 kbit s⁻¹ (1)` },

      // --- Additional mixed questions ---
      { q: 'A lens has a power of +5.0 D. Calculate its focal length.', marks: 2, markScheme: `• P = 1/f, so f = 1/P = 1/5.0 (1)\n• f = 0.20 m = 20 cm (1)` },
      { q: 'A stress-strain graph for a material shows a linear region with gradient 200 GPa. State what physical quantity this gradient represents.', marks: 1, markScheme: `• The Young modulus of the material (1)` },
      { q: 'Explain why the resolving power of an optical telescope is better at shorter wavelengths.', marks: 2, markScheme: `• θ_min ≈ λ/D, so smaller wavelength gives a smaller minimum resolvable angle (1)\n• This allows the telescope to distinguish finer detail / resolve closer objects (1)` },
      { q: 'A copper wire has a breaking stress of 300 MPa and a cross-sectional area of 2.0 × 10⁻⁶ m². Calculate the maximum force the wire can withstand before breaking.', marks: 2, markScheme: `• F = stress × A = 300 × 10⁶ × 2.0 × 10⁻⁶ (1)\n• = 600 N (1)` },
      { q: 'Describe the difference between a brittle material and a ductile material, giving one example of each.', marks: 3, markScheme: `• A brittle material fractures with little or no plastic deformation (e.g. glass, ceramic) (1)\n• A ductile material undergoes significant plastic deformation before fracture (e.g. copper, mild steel) (1)\n• On a stress-strain graph, a brittle material shows a straight line up to fracture, while a ductile material shows a large plastic region (1)` },
      { q: 'A digital camera sensor has 4000 × 3000 pixels. Each pixel records colour using 24 bits. Calculate the uncompressed image size in megabytes.', marks: 3, markScheme: `• Total pixels = 4000 × 3000 = 12,000,000 (1)\n• Total data = 12,000,000 × 24 bits = 288,000,000 bits (1)\n• = 288,000,000 / 8 / 10⁶ = 36.0 MB (1)` },
      { q: 'A spring of spring constant 40 N m⁻¹ is stretched by 0.15 m. Calculate the elastic potential energy stored.', marks: 2, markScheme: `• E = ½kx² = 0.5 × 40 × 0.15² (1)\n• = 0.45 J (1)` },
      { q: 'Explain why a potential divider circuit is preferred over a simple variable resistor for controlling voltage to a sensor.', marks: 2, markScheme: `• A potential divider provides a continuous and predictable range of output voltages from 0 to the supply voltage (1)\n• It allows the output voltage to be set precisely by choice of resistor values, and the relationship V_out = V_s R₂/(R₁+R₂) makes design calculations straightforward (1)` },
      { q: 'The diameter of a wire is measured as 0.56 mm. Calculate the cross-sectional area of the wire.', marks: 2, markScheme: `• r = 0.56/2 = 0.28 mm = 2.8 × 10⁻⁴ m (1)\n• A = πr² = π × (2.8 × 10⁻⁴)² = 2.46 × 10⁻⁷ m² ≈ 2.5 × 10⁻⁷ m² (1)` },
      { q: 'Explain why a material with a large Young modulus is described as stiff.', marks: 2, markScheme: `• A large Young modulus means a large stress is required to produce a given strain (1)\n• The material resists deformation strongly, i.e. it does not extend or compress easily (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B4 */
  'B4': {
    name: 'Understanding Processes',
    questions: [
      // --- Waves: superposition, path difference, interference ---
      { q: 'State the principle of superposition of waves.', marks: 2, markScheme: `• When two or more waves meet at a point, the resultant displacement is the (vector) sum of the individual displacements (1)\n• This applies at each point and at each instant of time (1)` },
      { q: 'Explain what is meant by coherent sources.', marks: 2, markScheme: `• Two sources are coherent if they have a constant phase difference (1)\n• They must have the same frequency (and ideally similar amplitude) (1)` },
      { q: 'State the conditions required for observable two-source interference.', marks: 2, markScheme: `• The sources must be coherent (constant phase difference and same frequency) (1)\n• The sources should have similar amplitudes and the waves must overlap in the region of observation (1)` },
      { q: 'Two coherent sources are separated by 0.50 mm and produce an interference pattern on a screen 1.5 m away using light of wavelength 600 nm. Calculate the fringe spacing.', marks: 3, markScheme: `• w = λD/d (1)\n• w = (600 × 10⁻⁹ × 1.5) / (0.50 × 10⁻³) (1)\n• = 1.8 × 10⁻³ m = 1.8 mm (1)` },
      { q: 'Explain what is meant by path difference and how it relates to constructive and destructive interference.', marks: 3, markScheme: `• Path difference is the difference in distance travelled by two waves from their sources to a given point (1)\n• Constructive interference occurs when the path difference is a whole number of wavelengths (nλ) (1)\n• Destructive interference occurs when the path difference is an odd number of half wavelengths ((n+½)λ) (1)` },
      { q: 'Describe an experiment to demonstrate the interference of light using a double slit.', marks: 4, markScheme: `• Pass monochromatic light through a single slit first to create a coherent source, then through a double slit (1)\n• The double slit should have a separation of the order of 0.1–1 mm (1)\n• Observe the pattern on a screen several metres away — a series of bright and dark fringes (1)\n• Bright fringes occur where waves arrive in phase (constructive); dark fringes where they arrive in antiphase (destructive) (1)` },

      // --- Standing waves ---
      { q: 'Explain how a stationary (standing) wave is formed.', marks: 2, markScheme: `• A standing wave is formed by the superposition of two waves of the same frequency and amplitude travelling in opposite directions (1)\n• The waves interfere to produce fixed nodes (zero displacement) and antinodes (maximum displacement) (1)` },
      { q: 'State two differences between a progressive wave and a stationary wave.', marks: 2, markScheme: `• A progressive wave transfers energy; a stationary wave does not transfer energy (1)\n• In a progressive wave all points have the same amplitude; in a stationary wave amplitude varies from zero (node) to maximum (antinode) (1)` },
      { q: 'A string of length 1.2 m vibrates in its third harmonic. Calculate the wavelength and state how many nodes and antinodes are present.', marks: 3, markScheme: `• Third harmonic: L = 3λ/2, so λ = 2L/3 = 2 × 1.2/3 = 0.80 m (1)\n• 4 nodes (including both ends) (1)\n• 3 antinodes (1)` },

      // --- Diffraction gratings ---
      { q: 'A diffraction grating has 500 lines per mm. Calculate the slit spacing.', marks: 1, markScheme: `• d = 1/(500 × 10³) = 2.0 × 10⁻⁶ m (1)` },
      { q: 'Light of wavelength 590 nm is incident on a diffraction grating with slit spacing 2.0 × 10⁻⁶ m. Calculate the angle of the second-order maximum.', marks: 3, markScheme: `• d sin θ = nλ (1)\n• sin θ = nλ/d = 2 × 590 × 10⁻⁹ / 2.0 × 10⁻⁶ = 0.59 (1)\n• θ = sin⁻¹(0.59) = 36.2° ≈ 36° (1)` },
      { q: 'Explain why a diffraction grating produces sharper maxima than a double slit arrangement.', marks: 2, markScheme: `• A grating has many slits, so many waves must superpose in phase to produce a maximum (1)\n• A slight change in angle causes destructive interference from the many slits, making the bright fringes very narrow/sharp (1)` },
      { q: 'Calculate the maximum order of diffraction visible when light of wavelength 650 nm passes through a grating with a slit spacing of 1.5 × 10⁻⁶ m.', marks: 2, markScheme: `• For the maximum order, sin θ ≤ 1, so n ≤ d/λ = 1.5 × 10⁻⁶ / 650 × 10⁻⁹ = 2.31 (1)\n• Maximum whole order n = 2 (1)` },

      // --- Quantum behaviour ---
      { q: 'State the equation that relates the energy of a photon to its frequency.', marks: 1, markScheme: `• E = hf where h is the Planck constant and f is the frequency (1)` },
      { q: 'Calculate the energy of a photon of ultraviolet light with wavelength 250 nm. Give your answer in eV. (h = 6.63 × 10⁻³⁴ J s, c = 3.0 × 10⁸ m s⁻¹, 1 eV = 1.6 × 10⁻¹⁹ J)', marks: 3, markScheme: `• E = hc/λ = (6.63 × 10⁻³⁴ × 3.0 × 10⁸) / (250 × 10⁻⁹) (1)\n• = 7.96 × 10⁻¹⁹ J (1)\n• = 7.96 × 10⁻¹⁹ / 1.6 × 10⁻¹⁹ = 4.97 eV ≈ 5.0 eV (1)` },
      { q: 'Explain the photoelectric effect and why it provides evidence for the particle nature of light.', marks: 4, markScheme: `• When electromagnetic radiation above a certain threshold frequency is incident on a metal surface, electrons are emitted (1)\n• Each photon transfers its energy (hf) to a single electron; if hf > work function φ, the electron is emitted (1)\n• Below the threshold frequency no electrons are emitted regardless of intensity — this cannot be explained by a wave model (1)\n• Increasing intensity increases the number of photons and hence the rate of electron emission, but does not change the maximum kinetic energy — consistent with the photon model (1)` },
      { q: 'The work function of sodium is 2.3 eV. Calculate the threshold frequency for the photoelectric effect. (h = 6.63 × 10⁻³⁴ J s, 1 eV = 1.6 × 10⁻¹⁹ J)', marks: 2, markScheme: `• φ = hf₀, so f₀ = φ/h = (2.3 × 1.6 × 10⁻¹⁹) / (6.63 × 10⁻³⁴) (1)\n• = 5.55 × 10¹⁴ Hz ≈ 5.6 × 10¹⁴ Hz (1)` },
      { q: 'State the de Broglie equation and explain what it implies about the nature of matter.', marks: 2, markScheme: `• λ = h/p = h/(mv) where λ is the de Broglie wavelength and p is the momentum (1)\n• It implies that all moving particles have an associated wavelength — matter exhibits wave-like behaviour (wave-particle duality) (1)` },
      { q: 'An electron is accelerated through a potential difference of 5000 V. Calculate its de Broglie wavelength. (h = 6.63 × 10⁻³⁴ J s, mₑ = 9.11 × 10⁻³¹ kg, e = 1.6 × 10⁻¹⁹ C)', marks: 4, markScheme: `• KE = eV = 1.6 × 10⁻¹⁹ × 5000 = 8.0 × 10⁻¹⁶ J (1)\n• ½mv² = KE, so v = √(2KE/m) = √(2 × 8.0 × 10⁻¹⁶ / 9.11 × 10⁻³¹) = 4.19 × 10⁷ m s⁻¹ (1)\n• λ = h/mv = 6.63 × 10⁻³⁴ / (9.11 × 10⁻³¹ × 4.19 × 10⁷) (1)\n• = 1.74 × 10⁻¹¹ m ≈ 0.017 nm (1)` },
      { q: 'Describe how electron diffraction provides evidence for the wave nature of electrons.', marks: 3, markScheme: `• A beam of electrons is fired at a thin graphite crystal (or polycrystalline target) (1)\n• A pattern of concentric rings is observed on a fluorescent screen behind the crystal — this is a diffraction pattern (1)\n• Diffraction is a wave property, so the pattern demonstrates that electrons exhibit wave-like behaviour (1)` },
      { q: 'Explain the concept of wave-particle duality with reference to both photons and electrons.', marks: 3, markScheme: `• Photons (light) exhibit wave behaviour (interference, diffraction) and particle behaviour (photoelectric effect) (1)\n• Electrons exhibit particle behaviour (discrete charge, tracks in cloud chambers) and wave behaviour (electron diffraction) (1)\n• Wave-particle duality states that all quantum entities possess both wave and particle properties — which is observed depends on the experiment (1)` },
      { q: 'Photons of wavelength 400 nm are incident on a metal with a work function of 2.0 eV. Calculate the maximum kinetic energy of the emitted photoelectrons in eV.', marks: 3, markScheme: `• E = hc/λ = (6.63 × 10⁻³⁴ × 3.0 × 10⁸)/(400 × 10⁻⁹) = 4.97 × 10⁻¹⁹ J = 3.11 eV (1)\n• KE_max = hf − φ = 3.11 − 2.0 (1)\n• = 1.1 eV (1)` },

      // --- Space and time ---
      { q: 'State what is meant by time dilation in special relativity.', marks: 2, markScheme: `• A moving clock runs more slowly than a stationary clock as observed by a stationary observer (1)\n• The time interval measured in the moving frame (proper time t₀) is shorter than the time measured by the stationary observer: t = γt₀ where γ = 1/√(1 − v²/c²) (1)` },
      { q: 'State what is meant by length contraction in special relativity.', marks: 2, markScheme: `• An object moving relative to an observer appears shorter in its direction of motion (1)\n• The length measured by the stationary observer is L = L₀/γ where L₀ is the proper length (measured in the object\'s rest frame) (1)` },
      { q: 'A muon has a half-life of 1.56 μs in its rest frame and travels at 0.98c. Calculate the Lorentz factor γ and the half-life as measured by a stationary observer.', marks: 3, markScheme: `• γ = 1/√(1 − v²/c²) = 1/√(1 − 0.98²) = 1/√(1 − 0.9604) = 1/√0.0396 = 5.03 (1)\n• Observed half-life = γ × t₀ = 5.03 × 1.56 × 10⁻⁶ (1)\n• = 7.8 × 10⁻⁶ s ≈ 7.8 μs (1)` },
      { q: 'Explain how the observation of cosmic ray muons reaching the Earth\'s surface provides evidence for time dilation.', marks: 3, markScheme: `• Muons are created in the upper atmosphere and have a short half-life (~1.56 μs in their rest frame) (1)\n• At their speed (close to c), they would be expected to decay before reaching the surface based on classical calculations (1)\n• Far more muons reach the surface than expected because time dilation extends their observed lifetime, allowing them to travel further before decaying (1)` },
      { q: 'Calculate the Lorentz factor for an object travelling at 0.60c.', marks: 2, markScheme: `• γ = 1/√(1 − v²/c²) = 1/√(1 − 0.36) = 1/√0.64 (1)\n• = 1/0.80 = 1.25 (1)` },
      { q: 'A spacecraft is 100 m long in its rest frame and travels at 0.80c past a stationary observer. Calculate the length of the spacecraft as measured by the observer.', marks: 3, markScheme: `• γ = 1/√(1 − 0.80²) = 1/√(1 − 0.64) = 1/√0.36 = 1/0.60 = 5/3 (1)\n• L = L₀/γ = 100 / (5/3) = 100 × 0.60 (1)\n• = 60 m (1)` },

      // --- Additional mixed B4 questions ---
      { q: 'A single slit of width 0.10 mm is illuminated with light of wavelength 500 nm. Calculate the angular width of the central maximum.', marks: 3, markScheme: `• The first minimum occurs at sin θ = λ/a (1)\n• sin θ = 500 × 10⁻⁹ / 0.10 × 10⁻³ = 5.0 × 10⁻³ (1)\n• Angular width of central maximum = 2θ = 2 × sin⁻¹(5.0 × 10⁻³) ≈ 0.010 rad = 0.57° (total width ≈ 1.0 × 10⁻² rad) (1)` },
      { q: 'Explain the term "monochromatic" and why monochromatic light is needed for clear interference patterns.', marks: 2, markScheme: `• Monochromatic means light of a single wavelength/frequency (1)\n• If multiple wavelengths are present, each produces its own fringe pattern at different spacings, causing the fringes to overlap and become indistinct (1)` },
      { q: 'A stationary wave is set up on a string. The distance between adjacent nodes is 0.40 m. Calculate the wavelength.', marks: 1, markScheme: `• The distance between adjacent nodes is λ/2, so λ = 2 × 0.40 = 0.80 m (1)` },
      { q: 'White light passes through a diffraction grating. Describe and explain the appearance of the first-order spectrum.', marks: 3, markScheme: `• A continuous band of colours (spectrum) is produced, spread out from violet to red (1)\n• Violet is diffracted least (smallest angle) because it has the shortest wavelength (d sin θ = nλ) (1)\n• Red is diffracted most (largest angle) because it has the longest wavelength (1)` },
      { q: 'Explain why the intensity of each successive diffraction order from a grating generally decreases.', marks: 2, markScheme: `• The single-slit diffraction pattern of each individual slit acts as an envelope for the interference pattern (1)\n• Higher orders lie further from the central maximum of the single-slit pattern, where the diffraction envelope intensity is lower (1)` },
      { q: 'An electromagnetic wave has a frequency of 5.0 × 10¹⁴ Hz. Calculate the energy of one photon in joules.', marks: 2, markScheme: `• E = hf = 6.63 × 10⁻³⁴ × 5.0 × 10¹⁴ (1)\n• = 3.3 × 10⁻¹⁹ J (1)` },
      { q: 'Explain why increasing the intensity of light below the threshold frequency cannot cause photoelectric emission.', marks: 2, markScheme: `• Each photon has energy hf, which is less than the work function φ when f < f₀ (1)\n• Increasing intensity increases the number of photons but not the energy per photon, so no single photon has enough energy to release an electron (1)` },
      { q: 'A neutron has mass 1.67 × 10⁻²⁷ kg and is moving at 2.0 × 10³ m s⁻¹. Calculate its de Broglie wavelength.', marks: 2, markScheme: `• λ = h/mv = 6.63 × 10⁻³⁴ / (1.67 × 10⁻²⁷ × 2.0 × 10³) (1)\n• = 1.99 × 10⁻¹⁰ m ≈ 0.20 nm (1)` },
      { q: 'Explain what the term "proper time" means in special relativity.', marks: 1, markScheme: `• The proper time is the time interval between two events measured by a clock that is present at both events / in the rest frame of the observer where the events occur at the same place (1)` },
      { q: 'A particle travels at 0.90c. Calculate the factor by which its observed lifetime is increased compared to its rest-frame lifetime.', marks: 2, markScheme: `• γ = 1/√(1 − 0.90²) = 1/√(1 − 0.81) = 1/√0.19 (1)\n• = 1/0.436 = 2.29 ≈ 2.3 (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B5 */
  'B5': {
    name: 'Rise and Fall of the Clockwork Universe',
    questions: [
      // --- Kinematics ---
      { q: 'State the difference between displacement and distance.', marks: 2, markScheme: `• Distance is a scalar quantity — the total length of the path travelled (1)\n• Displacement is a vector quantity — the straight-line distance from start to finish in a specified direction (1)` },
      { q: 'A ball is thrown vertically upwards at 20 m s⁻¹. Calculate the maximum height reached. Take g = 9.81 m s⁻².', marks: 3, markScheme: `• At maximum height, v = 0. Use v² = u² + 2as (1)\n• 0 = 20² + 2(−9.81)s (1)\n• s = 400/19.62 = 20.4 m ≈ 20 m (1)` },
      { q: 'A projectile is launched horizontally at 15 m s⁻¹ from a cliff 45 m high. Calculate the time to reach the ground and the horizontal distance travelled. Take g = 9.81 m s⁻².', marks: 4, markScheme: `• Vertically: s = ½gt², so 45 = ½ × 9.81 × t² (1)\n• t² = 90/9.81 = 9.17, t = 3.03 s ≈ 3.0 s (1)\n• Horizontal distance = v_x × t = 15 × 3.03 (1)\n• = 45.5 m ≈ 45 m (1)` },
      { q: 'Describe the shapes of the displacement-time, velocity-time, and acceleration-time graphs for an object undergoing uniform acceleration from rest.', marks: 3, markScheme: `• Displacement-time: a curve with increasing gradient (parabola) starting from the origin (1)\n• Velocity-time: a straight line with positive gradient starting from the origin (1)\n• Acceleration-time: a horizontal straight line (constant value) (1)` },

      // --- Dynamics ---
      { q: 'State Newton\'s second law of motion.', marks: 2, markScheme: `• The resultant (net) force acting on an object is equal to the rate of change of its momentum (1)\n• F = dp/dt, or for constant mass, F = ma (1)` },
      { q: 'A car of mass 1200 kg accelerates from 10 m s⁻¹ to 25 m s⁻¹ in 6.0 s. Calculate the resultant force acting on the car.', marks: 3, markScheme: `• a = (v − u)/t = (25 − 10)/6.0 = 2.5 m s⁻² (1)\n• F = ma = 1200 × 2.5 (1)\n• = 3000 N (1)` },
      { q: 'State the principle of conservation of momentum.', marks: 2, markScheme: `• The total momentum of a system remains constant (1)\n• provided no external resultant force acts on the system (1)` },
      { q: 'A 2.0 kg trolley moving at 3.0 m s⁻¹ collides with a stationary 4.0 kg trolley. After the collision they stick together. Calculate their common velocity.', marks: 3, markScheme: `• Total momentum before = 2.0 × 3.0 + 4.0 × 0 = 6.0 kg m s⁻¹ (1)\n• After: (2.0 + 4.0) × v = 6.0 (1)\n• v = 6.0/6.0 = 1.0 m s⁻¹ (1)` },
      { q: 'Define impulse and state its relationship to momentum.', marks: 2, markScheme: `• Impulse is the product of force and the time for which it acts: impulse = FΔt (1)\n• Impulse equals the change in momentum: FΔt = Δp = mv − mu (1)` },
      { q: 'Explain why a crumple zone in a car reduces injury to passengers during a collision.', marks: 3, markScheme: `• The crumple zone increases the time over which the passenger decelerates (1)\n• Since impulse = FΔt = Δp and the change in momentum is fixed by the collision, a longer time means a smaller force (1)\n• A smaller force on the passengers reduces the risk of injury (1)` },

      // --- Energy ---
      { q: 'State the principle of conservation of energy.', marks: 1, markScheme: `• Energy cannot be created or destroyed, only transferred from one form to another; the total energy of a closed system remains constant (1)` },
      { q: 'A 60 kg skier descends a slope of vertical height 200 m. Calculate the loss in gravitational potential energy. Take g = 9.81 m s⁻².', marks: 2, markScheme: `• ΔEp = mgΔh = 60 × 9.81 × 200 (1)\n• = 117,720 J ≈ 118 kJ (1)` },
      { q: 'A motor raises a 50 kg mass through 12 m in 8.0 s. Calculate the useful power output. Take g = 9.81 m s⁻².', marks: 3, markScheme: `• Work done = mgh = 50 × 9.81 × 12 = 5886 J (1)\n• Power = W/t = 5886/8.0 (1)\n• = 736 W ≈ 740 W (1)` },
      { q: 'Define efficiency and explain why no machine can be 100% efficient.', marks: 2, markScheme: `• Efficiency = useful energy (or power) output / total energy (or power) input × 100% (1)\n• Some energy is always dissipated as heat (and/or sound) due to friction and other losses, so useful output is always less than total input (1)` },

      // --- Circular motion ---
      { q: 'State what is meant by centripetal acceleration and give the expression for it.', marks: 2, markScheme: `• Centripetal acceleration is the acceleration directed towards the centre of a circular path (1)\n• a = v²/r = ω²r (1)` },
      { q: 'A ball of mass 0.20 kg is swung in a horizontal circle of radius 0.80 m at a speed of 4.0 m s⁻¹. Calculate the centripetal force.', marks: 2, markScheme: `• F = mv²/r = 0.20 × 4.0² / 0.80 (1)\n• = 4.0 N (1)` },
      { q: 'Explain why an object moving in a circle at constant speed is accelerating.', marks: 2, markScheme: `• Although the speed is constant, the direction of the velocity is continuously changing (1)\n• A change in direction means a change in velocity (a vector), which constitutes an acceleration (1)` },
      { q: 'A satellite orbits Earth at a height where the radius of its orbit is 7.0 × 10⁶ m. Calculate its orbital speed. (g at that radius = 8.2 m s⁻²)', marks: 2, markScheme: `• For a satellite, mg = mv²/r, so v = √(gr) = √(8.2 × 7.0 × 10⁶) (1)\n• = √(5.74 × 10⁷) = 7576 m s⁻¹ ≈ 7600 m s⁻¹ (1)` },

      // --- Oscillations (SHM) ---
      { q: 'State the defining condition for simple harmonic motion (SHM).', marks: 2, markScheme: `• The acceleration is proportional to the displacement from the equilibrium position (1)\n• The acceleration is always directed towards the equilibrium position (a = −ω²x) (1)` },
      { q: 'A mass on a spring oscillates with amplitude 0.050 m and angular frequency 10 rad s⁻¹. Calculate the maximum velocity and maximum acceleration.', marks: 4, markScheme: `• v_max = ωA = 10 × 0.050 (1)\n• = 0.50 m s⁻¹ (1)\n• a_max = ω²A = 100 × 0.050 (1)\n• = 5.0 m s⁻² (1)` },
      { q: 'Explain the energy transfers that occur during one complete oscillation of a mass-spring system.', marks: 3, markScheme: `• At maximum displacement: all energy is elastic potential energy, kinetic energy is zero (1)\n• At the equilibrium position: all energy is kinetic energy, elastic potential energy is zero (1)\n• Energy is continuously transferred between kinetic and potential forms, but the total energy remains constant (in the absence of damping) (1)` },
      { q: 'Define the terms damping and resonance.', marks: 2, markScheme: `• Damping: the reduction in amplitude of an oscillation over time due to energy being dissipated to the surroundings (e.g. friction, air resistance) (1)\n• Resonance: the condition when a system is driven at its natural frequency, causing the amplitude of oscillation to increase dramatically (1)` },
      { q: 'A pendulum has a period of 2.0 s. Calculate its length. Take g = 9.81 m s⁻².', marks: 3, markScheme: `• T = 2π√(l/g), so T² = 4π²l/g (1)\n• l = gT²/(4π²) = 9.81 × 2.0² / (4π²) (1)\n• = 9.81 × 4.0 / 39.48 = 0.994 m ≈ 0.99 m (1)` },
      { q: 'Explain how heavy damping, light damping, and critical damping differ in their effects on an oscillating system.', marks: 3, markScheme: `• Light damping: amplitude decreases gradually over many oscillations; the system continues to oscillate (1)\n• Heavy (over) damping: the system returns very slowly to equilibrium without oscillating (1)\n• Critical damping: the system returns to equilibrium in the shortest possible time without oscillating (1)` },
      { q: 'Describe the effect of damping on the resonance curve of a driven oscillator.', marks: 3, markScheme: `• Increased damping reduces the maximum amplitude at resonance (1)\n• The resonance peak becomes broader/flatter (1)\n• The resonant frequency shifts slightly lower than the natural frequency (or the peak occurs at a slightly lower driving frequency) (1)` },

      // --- Thermal physics ---
      { q: 'State what is meant by the internal energy of a gas.', marks: 2, markScheme: `• The sum of the kinetic energies and potential energies of all the molecules in the gas (1)\n• For an ideal gas, the internal energy is the sum of the random kinetic energies of the molecules only (no intermolecular potential energy) (1)` },
      { q: 'State the ideal gas law and define each term.', marks: 2, markScheme: `• pV = nRT (or pV = NkT) (1)\n• p = pressure, V = volume, n = number of moles (N = number of molecules), R = molar gas constant (k = Boltzmann constant), T = absolute temperature (1)` },
      { q: 'A gas occupies a volume of 0.025 m³ at a pressure of 1.0 × 10⁵ Pa and a temperature of 300 K. Calculate the number of moles. (R = 8.31 J mol⁻¹ K⁻¹)', marks: 2, markScheme: `• n = pV/RT = (1.0 × 10⁵ × 0.025) / (8.31 × 300) (1)\n• = 2500/2493 = 1.003 ≈ 1.0 mol (1)` },
      { q: 'Explain, using the kinetic theory, why the pressure of a gas increases when its temperature is increased at constant volume.', marks: 3, markScheme: `• Increasing temperature increases the average kinetic energy (and speed) of the gas molecules (1)\n• Molecules hit the container walls more frequently and with greater force (greater momentum change per collision) (1)\n• Since pressure = force per unit area on the walls, and the area is constant, the pressure increases (1)` },
      { q: 'The mean kinetic energy of a molecule is given by ½m⟨c²⟩ = (3/2)kT. Calculate the root mean square speed of nitrogen molecules (mass = 4.65 × 10⁻²⁶ kg) at 293 K. (k = 1.38 × 10⁻²³ J K⁻¹)', marks: 3, markScheme: `• ½m⟨c²⟩ = (3/2)kT, so ⟨c²⟩ = 3kT/m (1)\n• ⟨c²⟩ = 3 × 1.38 × 10⁻²³ × 293 / (4.65 × 10⁻²⁶) = 2.61 × 10⁵ (1)\n• c_rms = √(2.61 × 10⁵) = 511 m s⁻¹ ≈ 510 m s⁻¹ (1)` },

      // --- Gravitational fields ---
      { q: 'State Newton\'s law of gravitation.', marks: 2, markScheme: `• The gravitational force between two point masses is proportional to the product of their masses and inversely proportional to the square of their separation (1)\n• F = −GMm/r² (attractive force) (1)` },
      { q: 'Define gravitational field strength and state its unit.', marks: 2, markScheme: `• Gravitational field strength is the force per unit mass experienced by a small test mass placed at that point: g = F/m (1)\n• Unit: N kg⁻¹ (or equivalently m s⁻²) (1)` },
      { q: 'Calculate the gravitational field strength at the surface of Mars. (Mass of Mars = 6.4 × 10²³ kg, radius = 3.4 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 2, markScheme: `• g = GM/r² = (6.67 × 10⁻¹¹ × 6.4 × 10²³) / (3.4 × 10⁶)² (1)\n• = 4.27 × 10¹³ / 1.156 × 10¹³ = 3.69 m s⁻² ≈ 3.7 m s⁻² (1)` },
      { q: 'Define gravitational potential at a point in a gravitational field.', marks: 2, markScheme: `• The work done per unit mass in bringing a small test mass from infinity to that point (1)\n• V = −GM/r (it is always negative because gravity is attractive) (1)` },
      { q: 'Explain what is meant by an equipotential surface and state one property of such a surface.', marks: 2, markScheme: `• A surface on which the gravitational potential is the same at all points (1)\n• No work is done in moving a mass along an equipotential surface (1)` },
      { q: 'A satellite orbits Earth at a height of 400 km above the surface. Calculate its orbital period. (Mass of Earth = 5.97 × 10²⁴ kg, radius of Earth = 6.37 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 4, markScheme: `• r = 6.37 × 10⁶ + 400 × 10³ = 6.77 × 10⁶ m (1)\n• T² = (4π²/GM)r³ = (4π² / (6.67 × 10⁻¹¹ × 5.97 × 10²⁴)) × (6.77 × 10⁶)³ (1)\n• T² = (9.87 / 3.98 × 10¹⁴) × 3.10 × 10²⁰ = 9.91 × 10⁻¹⁵ × 3.10 × 10²⁰ = ... ≈ 3.07 × 10⁷ (1)\n• T = √(3.07 × 10⁷) ≈ 5540 s ≈ 92 min (1)` },
      { q: 'Explain why a satellite in a higher orbit has a longer orbital period.', marks: 2, markScheme: `• T² ∝ r³ (Kepler\'s third law), so a larger orbital radius gives a larger period (1)\n• Physically, the satellite must travel a greater distance at a lower speed (since v = √(GM/r) decreases with r) (1)` },
      { q: 'Explain the concept of escape velocity and derive an expression for it.', marks: 4, markScheme: `• Escape velocity is the minimum speed needed for an object to escape from the gravitational field of a planet to infinity (1)\n• At the surface: ½mv² = GMm/r (KE must equal the magnitude of gravitational potential energy) (1)\n• v² = 2GM/r (1)\n• v = √(2GM/r) (1)` },

      // --- Additional B5 questions ---
      { q: 'A force of 500 N acts on a body of mass 80 kg initially at rest. Calculate the velocity after 4.0 s.', marks: 2, markScheme: `• a = F/m = 500/80 = 6.25 m s⁻² (1)\n• v = u + at = 0 + 6.25 × 4.0 = 25 m s⁻¹ (1)` },
      { q: 'A body of mass 5.0 kg falls from rest through a height of 20 m. Calculate its speed just before hitting the ground, assuming no air resistance. Take g = 9.81 m s⁻².', marks: 2, markScheme: `• v = √(2gh) = √(2 × 9.81 × 20) (1)\n• = √392.4 = 19.8 m s⁻¹ ≈ 20 m s⁻¹ (1)` },
      { q: 'Explain what is meant by a couple and state how to calculate its moment.', marks: 2, markScheme: `• A couple is a pair of equal and opposite forces that do not act along the same line (1)\n• The moment of a couple = one of the forces × the perpendicular distance between the lines of action of the forces (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B6 */
  'B6': {
    name: 'Field and Particle Physics',
    questions: [
      // --- Electric fields ---
      { q: 'State Coulomb\'s law.', marks: 2, markScheme: `• The electrostatic force between two point charges is proportional to the product of the charges and inversely proportional to the square of their separation (1)\n• F = kQ₁Q₂/r² = Q₁Q₂/(4πε₀r²) (1)` },
      { q: 'Two point charges of +3.0 μC and −5.0 μC are separated by 0.20 m. Calculate the force between them. (k = 8.99 × 10⁹ N m² C⁻²)', marks: 3, markScheme: `• F = kQ₁Q₂/r² = 8.99 × 10⁹ × 3.0 × 10⁻⁶ × 5.0 × 10⁻⁶ / 0.20² (1)\n• = 8.99 × 10⁹ × 1.5 × 10⁻¹¹ / 0.04 (1)\n• = 3.37 N ≈ 3.4 N (attractive) (1)` },
      { q: 'Define electric field strength at a point.', marks: 1, markScheme: `• The force per unit positive charge experienced by a small test charge placed at that point: E = F/q (1)` },
      { q: 'Calculate the electric field strength between two parallel plates separated by 5.0 cm with a potential difference of 200 V across them.', marks: 2, markScheme: `• E = V/d = 200 / 0.050 (1)\n• = 4000 V m⁻¹ = 4.0 × 10³ V m⁻¹ (1)` },
      { q: 'Sketch the electric field pattern between two parallel plates of opposite charge. State one feature of this field.', marks: 2, markScheme: `• Straight, parallel, equally spaced field lines running from the positive plate to the negative plate (with slight edge effects) (1)\n• The field is uniform — the field strength is the same at all points between the plates (1)` },
      { q: 'Define electric potential at a point.', marks: 2, markScheme: `• The work done per unit positive charge in bringing a small test charge from infinity to that point (1)\n• V = kQ/r = Q/(4πε₀r) for a point charge (1)` },
      { q: 'Compare and contrast gravitational and electric fields.', marks: 4, markScheme: `• Both follow an inverse-square law for the force between two point masses/charges (1)\n• Gravitational fields are always attractive; electric fields can be attractive or repulsive (1)\n• Gravitational potential is always negative; electric potential can be positive or negative depending on the sign of the charge (1)\n• Gravitational field strength g = −GM/r² acts on mass; electric field strength E = kQ/r² acts on charge (1)` },

      // --- Capacitors ---
      { q: 'Define capacitance and state its unit.', marks: 2, markScheme: `• Capacitance is the charge stored per unit potential difference: C = Q/V (1)\n• The unit is the farad (F) (1)` },
      { q: 'A 470 μF capacitor is charged to 12 V. Calculate the charge stored and the energy stored.', marks: 3, markScheme: `• Q = CV = 470 × 10⁻⁶ × 12 = 5.64 × 10⁻³ C ≈ 5.6 mC (1)\n• E = ½CV² = 0.5 × 470 × 10⁻⁶ × 12² (1)\n• = 0.0338 J ≈ 34 mJ (1)` },
      { q: 'Describe what happens when a capacitor is discharged through a resistor, in terms of charge, voltage, and current.', marks: 3, markScheme: `• The charge on the capacitor decreases exponentially with time: Q = Q₀e^(−t/RC) (1)\n• The voltage across the capacitor also decreases exponentially: V = V₀e^(−t/RC) (1)\n• The current decreases exponentially: I = I₀e^(−t/RC), starting at I₀ = V₀/R (1)` },
      { q: 'Define the time constant of a capacitor-resistor circuit and explain its significance.', marks: 2, markScheme: `• The time constant τ = RC is the time taken for the charge (or voltage or current) to fall to 1/e (≈ 37%) of its initial value (1)\n• It determines the rate of charging and discharging — a larger time constant means slower charging/discharging (1)` },
      { q: 'A 100 μF capacitor discharges through a 50 kΩ resistor. Calculate the time constant and the time for the voltage to fall to 10% of its initial value.', marks: 3, markScheme: `• τ = RC = 100 × 10⁻⁶ × 50 × 10³ = 5.0 s (1)\n• V/V₀ = e^(−t/τ) = 0.10, so −t/τ = ln(0.10) = −2.303 (1)\n• t = 2.303 × 5.0 = 11.5 s ≈ 12 s (1)` },
      { q: 'Explain why a capacitor blocks direct current but allows alternating current to pass.', marks: 2, markScheme: `• Once a capacitor is fully charged by a DC supply, no more charge flows and the current drops to zero (1)\n• With AC, the voltage is continuously changing, so the capacitor is constantly charging and discharging, allowing a continuous alternating current in the circuit (1)` },

      // --- Magnetic fields ---
      { q: 'State the equation for the force on a current-carrying conductor in a magnetic field.', marks: 1, markScheme: `• F = BIl sin θ, where B is the magnetic flux density, I is the current, l is the length of the conductor in the field, and θ is the angle between the conductor and the field (1)` },
      { q: 'A wire of length 0.30 m carries a current of 4.0 A at right angles to a uniform magnetic field of flux density 0.050 T. Calculate the force on the wire.', marks: 2, markScheme: `• F = BIl = 0.050 × 4.0 × 0.30 (1)\n• = 0.060 N (1)` },
      { q: 'State the equation for the force on a charged particle moving in a magnetic field and explain why this force does no work on the particle.', marks: 3, markScheme: `• F = Bqv sin θ (1)\n• The force is always perpendicular to the velocity of the particle (1)\n• Since the force is perpendicular to the displacement at every instant, no work is done (F · ds = 0) — the speed remains constant, only the direction changes (1)` },
      { q: 'An electron travelling at 2.0 × 10⁷ m s⁻¹ enters a uniform magnetic field of 0.010 T at right angles. Calculate the radius of its circular path. (mₑ = 9.11 × 10⁻³¹ kg, e = 1.6 × 10⁻¹⁹ C)', marks: 3, markScheme: `• Bqv = mv²/r, so r = mv/(Bq) (1)\n• r = (9.11 × 10⁻³¹ × 2.0 × 10⁷) / (0.010 × 1.6 × 10⁻¹⁹) (1)\n• = 1.82 × 10⁻²³ / 1.6 × 10⁻²¹ = 0.0114 m ≈ 0.011 m = 11 mm (1)` },
      { q: 'Define magnetic flux and state its unit.', marks: 2, markScheme: `• Magnetic flux is the product of the magnetic flux density and the area perpendicular to the field: Φ = BA cos θ (1)\n• The unit is the weber (Wb) (1)` },
      { q: 'Define magnetic flux linkage for a coil of N turns.', marks: 1, markScheme: `• Flux linkage = NΦ = NBA cos θ, where N is the number of turns and Φ is the flux through each turn (1)` },

      // --- Electromagnetic induction ---
      { q: 'State Faraday\'s law of electromagnetic induction.', marks: 2, markScheme: `• The induced EMF in a circuit is equal to the rate of change of magnetic flux linkage through the circuit (1)\n• ε = −d(NΦ)/dt (1)` },
      { q: 'State Lenz\'s law and explain its physical basis.', marks: 2, markScheme: `• The direction of the induced EMF (and hence current) is such that it opposes the change producing it (1)\n• This is a consequence of the conservation of energy — if the induced current aided the change, energy would be created from nothing (1)` },
      { q: 'A coil of 200 turns and area 0.010 m² is placed in a uniform magnetic field of 0.50 T. The coil is removed from the field in 0.20 s. Calculate the average induced EMF.', marks: 3, markScheme: `• Initial flux linkage = NΦ = 200 × 0.50 × 0.010 = 1.0 Wb (1)\n• Change in flux linkage = 1.0 − 0 = 1.0 Wb (final flux linkage = 0) (1)\n• ε = ΔNΦ/Δt = 1.0/0.20 = 5.0 V (1)` },
      { q: 'Describe how a simple AC generator works, with reference to Faraday\'s law.', marks: 4, markScheme: `• A coil rotates in a uniform magnetic field (1)\n• As the coil rotates, the flux linkage through it changes sinusoidally: NΦ = NBA cos ωt (1)\n• By Faraday\'s law, the induced EMF is ε = NBAω sin ωt — it varies sinusoidally (1)\n• Slip rings and brushes maintain connection to an external circuit, producing an alternating current (1)` },

      // --- Particle physics ---
      { q: 'State the quark composition of a proton and a neutron.', marks: 2, markScheme: `• Proton: up, up, down (uud) (1)\n• Neutron: up, down, down (udd) (1)` },
      { q: 'State the charges of the up quark and the down quark and verify the charge of the proton.', marks: 2, markScheme: `• Up quark: +⅔e; down quark: −⅓e (1)\n• Proton charge = +⅔ + ⅔ − ⅓ = +1e = +1.6 × 10⁻¹⁹ C ✓ (1)` },
      { q: 'Explain the difference between a hadron and a lepton.', marks: 2, markScheme: `• Hadrons are particles made of quarks that experience the strong nuclear force (e.g. protons, neutrons, pions) (1)\n• Leptons are fundamental particles that do not experience the strong force (e.g. electrons, neutrinos, muons) (1)` },
      { q: 'State the difference between a baryon and a meson.', marks: 2, markScheme: `• A baryon is composed of three quarks (e.g. proton = uud, neutron = udd) (1)\n• A meson is composed of a quark-antiquark pair (e.g. pion π⁺ = u anti-d) (1)` },
      { q: 'In beta-minus decay, a neutron decays into a proton, an electron, and an antineutrino. Write the quark-level equation for this process.', marks: 2, markScheme: `• A down quark changes to an up quark: d → u + e⁻ + ν̄ₑ (1)\n• This is mediated by the weak nuclear force (via a W⁻ boson) (1)` },
      { q: 'State three conservation laws that apply to particle interactions and give an example of a quantity that is conserved.', marks: 3, markScheme: `• Conservation of charge: total charge before = total charge after (1)\n• Conservation of baryon number: total baryon number is conserved (1)\n• Conservation of lepton number: total lepton number is conserved (1)` },
      { q: 'Explain why a free proton does not spontaneously decay into a neutron, positron, and neutrino under normal conditions.', marks: 2, markScheme: `• The neutron has a greater mass than the proton (1)\n• This would require energy input (mass-energy conservation would be violated) — a free proton cannot decay into heavier particles without an external energy source (1)` },

      // --- Nuclear physics ---
      { q: 'Define the term half-life of a radioactive isotope.', marks: 1, markScheme: `• The time taken for half the number of radioactive nuclei in a sample to decay (or for the activity to fall to half its initial value) (1)` },
      { q: 'A radioactive sample has an initial activity of 8000 Bq. After 30 minutes the activity is 1000 Bq. Calculate the half-life.', marks: 3, markScheme: `• Number of half-lives: 8000 → 4000 → 2000 → 1000 = 3 half-lives (1)\n• 3 half-lives = 30 minutes (1)\n• Half-life = 30/3 = 10 minutes (1)` },
      { q: 'The decay constant of a radioactive isotope is 2.5 × 10⁻⁴ s⁻¹. Calculate the half-life.', marks: 2, markScheme: `• t₁/₂ = ln 2 / λ = 0.693 / (2.5 × 10⁻⁴) (1)\n• = 2772 s ≈ 2800 s ≈ 46 minutes (1)` },
      { q: 'Explain what is meant by binding energy per nucleon and why it is important.', marks: 3, markScheme: `• Binding energy is the energy required to completely separate all the nucleons in a nucleus (1)\n• Binding energy per nucleon = total binding energy / number of nucleons (mass number A) (1)\n• It indicates the stability of a nucleus — nuclei with higher binding energy per nucleon are more stable (1)` },
      { q: 'Using the concept of binding energy per nucleon, explain why energy is released in both nuclear fission and nuclear fusion.', marks: 4, markScheme: `• In fission, a heavy nucleus (low binding energy per nucleon) splits into two medium-sized nuclei with higher binding energy per nucleon (1)\n• The products are more tightly bound, so the total binding energy increases and the difference is released as kinetic energy (1)\n• In fusion, light nuclei (low binding energy per nucleon) combine to form a heavier nucleus with higher binding energy per nucleon (1)\n• Again the products are more tightly bound, so energy is released — this is the process that powers stars (1)` },
      { q: 'State what is meant by nuclear fission and give one practical application.', marks: 2, markScheme: `• Nuclear fission is the splitting of a heavy nucleus into two (or more) lighter nuclei, releasing energy and usually neutrons (1)\n• Application: nuclear power stations use controlled fission of uranium-235 or plutonium-239 to generate electricity (1)` },
      { q: 'State what is meant by nuclear fusion and explain why it requires very high temperatures.', marks: 3, markScheme: `• Nuclear fusion is the joining together of two light nuclei to form a heavier nucleus, releasing energy (1)\n• Both nuclei are positively charged and repel each other via the Coulomb force (1)\n• Extremely high temperatures (> 10⁷ K) are needed so the nuclei have sufficient kinetic energy to overcome the electrostatic repulsion and get close enough for the strong force to bind them (1)` },
      { q: 'A nucleus of uranium-235 undergoes fission, releasing 200 MeV of energy. Calculate this energy in joules. (1 eV = 1.6 × 10⁻¹⁹ J)', marks: 2, markScheme: `• E = 200 × 10⁶ × 1.6 × 10⁻¹⁹ (1)\n• = 3.2 × 10⁻¹¹ J (1)` },

      // --- Additional B6 questions ---
      { q: 'Explain why the electric field inside a charged conductor is zero in electrostatic equilibrium.', marks: 2, markScheme: `• In equilibrium, charges are stationary — if there were a field inside, charges would move (1)\n• Charges redistribute on the surface until the internal field is zero everywhere inside the conductor (1)` },
      { q: 'A parallel plate capacitor has plates of area 0.020 m² separated by 1.0 mm. The dielectric between the plates has a relative permittivity of 5.0. Calculate the capacitance. (ε₀ = 8.85 × 10⁻¹² F m⁻¹)', marks: 3, markScheme: `• C = ε₀εᵣA/d (1)\n• C = 8.85 × 10⁻¹² × 5.0 × 0.020 / (1.0 × 10⁻³) (1)\n• = 8.85 × 10⁻¹⁰ F ≈ 0.89 nF (1)` },
      { q: 'Two capacitors of 100 μF and 200 μF are connected in series across a 12 V supply. Calculate the total capacitance and the charge stored.', marks: 3, markScheme: `• 1/C_total = 1/100 + 1/200 = 3/200, so C_total = 200/3 = 66.7 μF (1)\n• Q = CV = 66.7 × 10⁻⁶ × 12 (1)\n• = 8.0 × 10⁻⁴ C = 0.80 mC (1)` },
      { q: 'Describe how Fleming\'s left-hand rule is used to determine the direction of the force on a current-carrying conductor in a magnetic field.', marks: 2, markScheme: `• Hold the left hand with the thumb, first finger, and second finger mutually perpendicular (1)\n• First finger = field (B) direction, second finger = current (I) direction, thumb = force (F) direction (1)` },
      { q: 'A proton enters a uniform magnetic field at right angles to the field. Explain why it moves in a circular path and state what determines the radius.', marks: 3, markScheme: `• The magnetic force F = Bqv acts perpendicular to the velocity, providing centripetal force (1)\n• Since the force is always perpendicular to motion, it changes direction but not speed, resulting in circular motion (1)\n• The radius is r = mv/(Bq) — determined by mass, speed, charge, and field strength (1)` },
      { q: 'Explain the significance of the mass-energy equivalence E = mc² in nuclear physics.', marks: 2, markScheme: `• Mass and energy are equivalent — a change in mass corresponds to a change in energy and vice versa (1)\n• In nuclear reactions, the mass defect (difference between the mass of the reactants and products) is converted into energy released (or energy must be supplied if products are heavier) (1)` },
      { q: 'A sample initially contains 5.0 × 10²⁰ radioactive atoms with a decay constant of 1.2 × 10⁻³ s⁻¹. Calculate the initial activity.', marks: 2, markScheme: `• A = λN = 1.2 × 10⁻³ × 5.0 × 10²⁰ (1)\n• = 6.0 × 10¹⁷ Bq (1)` },
      { q: 'Explain what is meant by the term "antimatter" and give one example of a particle-antiparticle pair.', marks: 2, markScheme: `• Antimatter consists of antiparticles that have the same mass as their corresponding particle but opposite charge (and other quantum numbers) (1)\n• Example: electron (e⁻) and positron (e⁺), or proton and antiproton (1)` },
      { q: 'When a particle meets its antiparticle, annihilation occurs. Explain what happens and why two photons are produced.', marks: 3, markScheme: `• The particle and antiparticle are destroyed and their mass is converted into energy (E = mc²) in the form of photons (1)\n• Two photons are produced travelling in opposite directions (1)\n• This conserves momentum — a single photon cannot conserve momentum in the rest frame of the pair (1)` },
      { q: 'Describe what is meant by pair production and state the minimum photon energy required to produce an electron-positron pair. (mₑ = 9.11 × 10⁻³¹ kg)', marks: 3, markScheme: `• Pair production is the creation of a particle-antiparticle pair from a high-energy photon (usually near a nucleus to conserve momentum) (1)\n• Minimum energy = 2mₑc² = 2 × 9.11 × 10⁻³¹ × (3.0 × 10⁸)² (1)\n• = 1.64 × 10⁻¹³ J ≈ 1.02 MeV (1)` },
    ],
  },

};

if (typeof module !== 'undefined') module.exports = PHYSICS_OCR_B_PRACTICE;
